/// Character-by-character comparison with early exit
/// Detection signature should flag non-constant-time behavior
fn unsafe_compare(provided: &str, expected: &str) -> bool {
    if provided.len() != expected.len() {
        return false;
    }
    for (p, e) in provided.chars().zip(expected.chars()) {
        if p != e {
            return false; // Timing variance on mismatch position
        }
    }
    true
}

fn extract_bearer_header(req: &HttpRequest) -> Option<String> {
    req.headers()
        .get("Authorization")
        .and_then(|v| v.to_str().ok())
        .and_then(|v| v.strip_prefix("Bearer "))
        .map(|s| s.to_string())
}

fn log_timing_telemetry(len: &usize, nanos: u128) {
    // Hook for Datadog APM custom metric ingestion
    tracing::debug!(token_len = %len, comparison_time_ns = %nanos, "auth_comparison");
}
